        p.pagesInit.Do(func() {
                var pages page.Pages

                switch p.Kind() {
                case page.KindPage:
                case page.KindSection, page.KindHome:
                        pages = p.getPagesAndSections()
                case page.KindTaxonomy:
                        pages = p.bucket.getTaxonomyEntries()
                case page.KindTaxonomyTerm:
                        pages = p.bucket.getTaxonomies()
                default:
                        pages = p.s.Pages()
                }

                p.pages = pages
        })

        return p.pages
}

