	} else {
		c.m.collectPages(c.key+cmBranchSeparator, func(c *contentNode) {
			pas = append(pas, c.p)
		})
		c.m.collectPages(c.key+"/", func(c *contentNode) {
			pas = append(pas, c.p)
		})
	}

	page.SortByDefault(pas)

	return pas
}

